// Some portions generated by Claude Code
package org.eclipse.rdf4j.query.algebra.evaluation.iterator;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayList;
import java.util.List;
import java.util.NoSuchElementException;

import org.eclipse.rdf4j.common.iteration.CloseableIteration;
import org.eclipse.rdf4j.common.iteration.CloseableIteratorIteration;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.junit.jupiter.api.Test;

/**
 * Tests that {@link PeekMarkIterator} forwards the advisory
 * {@link CloseableIteration#seek(Value, boolean, Value, boolean)} hint only when its own peek/mark/replay state cannot
 * owe any element to the caller.
 */
public class PeekMarkIteratorSeekTest {

	/**
	 * A seek-capable iteration over sorted strings. The honored min bound drops elements that compare below the bound's
	 * string value; every forwarded call is recorded.
	 */
	private static final class RecordingSeekIteration implements CloseableIteration<String> {

		private final List<String> elements;
		private final List<String> seekTargets = new ArrayList<>();
		private int index;

		private RecordingSeekIteration(List<String> elements) {
			this.elements = elements;
		}

		@Override
		public boolean hasNext() {
			return index < elements.size();
		}

		@Override
		public String next() {
			if (!hasNext()) {
				throw new NoSuchElementException();
			}
			return elements.get(index++);
		}

		@Override
		public void seek(Value minValue, boolean minInclusive, Value maxValue, boolean maxInclusive) {
			if (minValue == null) {
				return;
			}
			String min = minValue.stringValue();
			seekTargets.add(min);
			while (index < elements.size()) {
				int compare = elements.get(index).compareTo(min);
				if (compare < 0 || (compare == 0 && !minInclusive)) {
					index++;
				} else {
					break;
				}
			}
		}

		@Override
		public boolean supportsSeek() {
			return true;
		}

		@Override
		public void close() {
		}
	}

	private static Value literal(String value) {
		return SimpleValueFactory.getInstance().createLiteral(value);
	}

	@Test
	public void forwardsWhenIdleAfterNext() {
		RecordingSeekIteration inner = new RecordingSeekIteration(List.of("a", "b", "c", "d", "e"));
		try (PeekMarkIterator<String> iterator = new PeekMarkIterator<>(inner)) {
			assertEquals("a", iterator.next());
			iterator.seek(literal("d"), true, null, true);
			assertEquals(List.of("d"), inner.seekTargets);
			assertEquals("d", iterator.next());
			assertEquals("e", iterator.next());
			assertFalse(iterator.hasNext());
		}
	}

	@Test
	public void declinesWhilePeeked() {
		RecordingSeekIteration inner = new RecordingSeekIteration(List.of("a", "b", "c"));
		try (PeekMarkIterator<String> iterator = new PeekMarkIterator<>(inner)) {
			assertEquals("a", iterator.peek());
			iterator.seek(literal("c"), true, null, true);
			assertTrue(inner.seekTargets.isEmpty());
			assertEquals("a", iterator.next());
			assertEquals("b", iterator.next());
		}
	}

	@Test
	public void declinesWhileMarked() {
		RecordingSeekIteration inner = new RecordingSeekIteration(List.of("a", "b", "c", "d", "e"));
		try (PeekMarkIterator<String> iterator = new PeekMarkIterator<>(inner)) {
			assertEquals("a", iterator.next());
			iterator.mark();
			assertEquals("b", iterator.next());
			iterator.seek(literal("e"), true, null, true);
			assertTrue(inner.seekTargets.isEmpty());
			iterator.reset();
			assertEquals("b", iterator.next());
			assertEquals("c", iterator.next());
		}
	}

	@Test
	public void declinesDuringBufferReplayAndWhileResetPossible() {
		RecordingSeekIteration inner = new RecordingSeekIteration(List.of("a", "b", "c", "d", "e", "f"));
		try (PeekMarkIterator<String> iterator = new PeekMarkIterator<>(inner)) {
			assertEquals("a", iterator.next());
			iterator.mark();
			assertEquals("b", iterator.next());
			assertEquals("c", iterator.next());
			iterator.reset();

			// replaying the buffer
			iterator.seek(literal("f"), true, null, true);
			assertTrue(inner.seekTargets.isEmpty());
			assertEquals("b", iterator.next());
			assertEquals("c", iterator.next());

			// buffer drained, but reset is still possible
			iterator.seek(literal("f"), true, null, true);
			assertTrue(inner.seekTargets.isEmpty());
			iterator.reset();
			assertEquals("b", iterator.next());
			assertEquals("c", iterator.next());
		}
	}

	@Test
	public void forwardsAgainAfterUnmark() {
		RecordingSeekIteration inner = new RecordingSeekIteration(List.of("a", "b", "c", "d", "e", "f"));
		try (PeekMarkIterator<String> iterator = new PeekMarkIterator<>(inner)) {
			assertEquals("a", iterator.next());
			iterator.mark();
			assertEquals("b", iterator.next());
			iterator.unmark();

			iterator.seek(literal("e"), true, null, true);
			assertEquals(List.of("e"), inner.seekTargets);
			assertEquals("e", iterator.next());
			assertEquals("f", iterator.next());
			assertFalse(iterator.hasNext());
		}
	}

	@Test
	public void supportsSeekDelegates() {
		try (PeekMarkIterator<String> plain = new PeekMarkIterator<>(
				new CloseableIteratorIteration<>(List.of("a").iterator()))) {
			assertFalse(plain.supportsSeek());
		}

		PeekMarkIterator<String> seekable = new PeekMarkIterator<>(new RecordingSeekIteration(List.of("a")));
		assertTrue(seekable.supportsSeek());
		seekable.close();
		assertFalse(seekable.supportsSeek());
	}

	@Test
	public void closedSeekIsANoOp() {
		RecordingSeekIteration inner = new RecordingSeekIteration(List.of("a", "b"));
		PeekMarkIterator<String> iterator = new PeekMarkIterator<>(inner);
		iterator.close();
		iterator.seek(literal("b"), true, null, true);
		assertTrue(inner.seekTargets.isEmpty());
	}
}
